2804	% --- Mathlib dependency anchors for the gap1 slice-transport route ---
2805	
2806	\begin{lemma}[Pullback of sheaves of modules along a morphism of schemes]
2807	  \label{lem:modules_pullback_mathlib}
2808	  \lean{AlgebraicGeometry.Scheme.Modules.pullback}
2809	  \mathlibok
2810	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
2811	  For a morphism of schemes \(f : X \to Y\), Mathlib supplies the pullback functor
2812	  \(f^{*} : Y.\mathrm{Modules} \to X.\mathrm{Modules}\) on sheaves of modules, left adjoint to
2813	  pushforward, hence colimit-preserving, and carrying the unit sheaf to the unit sheaf. The project
2814	  already uses this functor in the definition of local freeness. It is the geometric restriction
2815	  through which a presentation is transported to an open subscheme.
2816	\end{lemma}
2817	
2818	\begin{lemma}[Restriction of sheaves of modules along an open immersion]
2819	  \label{lem:modules_restrictFunctor_mathlib}
2820	  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctor}
2821	  \mathlibok
2822	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
2823	  For an open immersion \(f : X \to Y\), Mathlib supplies the restriction functor
2824	  \(f^{\mathrm{res}} : Y.\mathrm{Modules} \to X.\mathrm{Modules}\), with
2825	  \(\Gamma(f^{\mathrm{res}} M, U) = \Gamma(M, f(U))\) definitionally; it is a left adjoint (colimit
2826	  preserving) and carries the unit sheaf to the unit sheaf. This is the geometric
2827	  ``restrict to open \(U\)'' functor on \((\Spec R).\mathrm{Modules}\).
2828	\end{lemma}
2829	
2830	\begin{lemma}[Restriction is isomorphic to pullback]
2831	  \label{lem:modules_restrictFunctorIsoPullback_mathlib}
2832	  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctorIsoPullback}
2833	  \mathlibok
2834	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
2835	  For an open immersion \(f\), the restriction functor (\cref{lem:modules_restrictFunctor_mathlib})
2836	  is naturally isomorphic to the pullback functor (\cref{lem:modules_pullback_mathlib}):
2837	  \(f^{\mathrm{res}} \cong f^{*}\). This identifies the restriction functor with the
2838	  universal-property pullback, so a presentation transported along one transports along the other.
2839	\end{lemma}
