2841	\begin{lemma}[Transport of a presentation along a colimit-preserving functor]
2842	  \label{lem:presentation_map_mathlib}
2843	  \lean{SheafOfModules.Presentation.map}
2844	  \mathlibok
2845	  \textit{Provided by Mathlib (\texttt{Mathlib.Algebra.Category.ModuleCat.Sheaf.Quasicoherent}).}
2846	  Let \(F\) be a functor between categories of sheaves of modules that preserves colimits and is
2847	  equipped with an isomorphism \(\eta : F(\mathrm{unit}_R) \cong \mathrm{unit}_S\) sending the unit
2848	  sheaf to the unit sheaf. Then any presentation \(P : \mathrm{Presentation}\,M\) (a
2849	  cokernel-of-free-modules description) induces a presentation
2850	  \(P.\mathrm{map}\,F\,\eta : \mathrm{Presentation}\,(F(M))\) of the image. Applied to the pullback
2851	  and restriction functors (\cref{lem:modules_pullback_mathlib},
2852	  \cref{lem:modules_restrictFunctor_mathlib}), it is how a presentation of \(M\) over one site is
2853	  carried to a presentation over another.
2854	\end{lemma}
2855	
2856	\begin{lemma}[Slice-presentation transport for quasi-coherence data]
2857	  \label{lem:quasicoherentData_bind_mathlib}
2858	  \lean{SheafOfModules.QuasicoherentData.bind}
2859	  \mathlibok
2860	  \textit{Provided by Mathlib (\texttt{Mathlib.Algebra.Category.ModuleCat.Sheaf.Quasicoherent}).}
2861	  Mathlib's \(\mathrm{QuasicoherentData.bind}\) transports a presentation across an iterated
2862	  Grothendieck slice: from quasi-coherence data on a cover \(\{X_i\}\) and, for each \(i\), data on a
2863	  cover of \(M.\mathrm{over}\,X_i\), it assembles quasi-coherence data on the composite cover, by
2864	  applying \(\mathrm{Presentation.map}\) (\cref{lem:presentation_map_mathlib}) along the equivalence
2865	  \(\mathrm{pushforwardPushforwardEquivalence}(\mathrm{Over.iteratedSliceEquiv}\,\cdots)\). It is the
2866	  worked template for the per-element presentation transport used in \cref{lem:over_restrict_iso} and
2867	  \cref{lem:isIso_fromTildeΓ_basicOpen_of_quasicoherent}, handling the slice-site adjointness and
2868	  sheafification typeclass synthesis.
2869	\end{lemma}
2870	
2871	\begin{lemma}[Localization is flat]
2872	  \label{lem:isLocalization_flat_mathlib}
2873	  \lean{IsLocalization.flat}
2874	  \mathlibok
2875	  \textit{Provided by Mathlib (\texttt{Mathlib.RingTheory.Flat.Localization}).}
2876	  If \(S\) is a localization of a commutative ring \(R\) at a multiplicative submonoid, then \(S\) is
2877	  a flat \(R\)-module. Consequently localization is exact and commutes with finite limits; this is
2878	  what lets the section-localization functor pass through the finite sheaf equalizer in the descent
2879	  (\cref{lem:section_localization_descent}).
2880	\end{lemma}
