2882	% --- The finite basic-open cover (topological precursor) ---
2883	
2884	\begin{lemma}
2885	
2886	\leanok
2887	[Finite basic-open cover refining a quasi-coherence cover]
2888	  \label{lem:exists_finite_basicOpen_cover_le_quasicoherentData}
2889	  \lean{AlgebraicGeometry.exists_finite_basicOpen_cover_le_quasicoherentData}
2890	  \uses{lem:isQuasicoherent_quasicoherentData_mathlib, lem:isBasis_basic_opens_mathlib}
2891	  \textit{The topological finite-cover front of the gap1 transport: any quasi-coherence cover refines
2892	  to a finite basic-open cover.}
2893	  Let \(M\) be a sheaf of modules on \(\Spec R\) and let \(q\) be quasi-coherence data for \(M\)
2894	  (\cref{lem:isQuasicoherent_quasicoherentData_mathlib}): a — possibly infinite — open cover
2895	  \(\{q.X_i\}\) of \(\top\) together with a presentation of \(M.\mathrm{over}\,(q.X_i)\) on each
2896	  member. Then there is a \emph{finite} subset \(t \subseteq R\) whose basic opens cover \(\Spec R\)
2897	  (equivalently \(\mathrm{span}\,t = (1)\)) such that each \(D(r)\), \(r \in t\), is contained in some
2898	  member \(q.X_i\) of the presentation cover.
2899	\end{lemma}
2900	\begin{proof}
2901	  \uses{lem:isBasis_basic_opens_mathlib}
2902	  The set \(G = \{\,r \in R : D(r) \le q.X_i \text{ for some } i\,\}\) spans the unit ideal. Indeed
2903	  every prime of \(R\) lies in some member \(q.X_i\) by the covering property \(q.\mathrm{coversTop}\)
2904	  (read off the \(\mathrm{Opens}\) Grothendieck-topology sieve), and the basic opens form a basis of
2905	  the Zariski topology (\cref{lem:isBasis_basic_opens_mathlib}), so a basic open \(D(r) \subseteq
2906	  q.X_i\) is a neighbourhood of that prime; hence \(\bigsqcup_{r \in G} D(r) = \top\), which is to say
2907	  \(\mathrm{span}\,G = (1)\). A unit-ideal membership uses only finitely many of the generators,
2908	  yielding a finite \(t \subseteq G\) with \(\mathrm{span}\,t = (1)\) and each \(D(r) \le q.X_i\) for
2909	  \(r \in t\).
2910	\end{proof}
