2912	% --- The over-site/open-subspace sheaf equivalence (bridge C, topological layer) ---
2913	
2914	% The blocks in this sub-section record the project-local infrastructure that fills the explicit
2915	% TODO of Mathlib's `Topology/Sheaves/Over.lean`: the equivalence of sheaf categories induced by
2916	% the site equivalence `Opens.overEquivalence U`. Together with the three Mathlib dependency
2917	% anchors below they form the topos-theoretic (purely topological) layer of bridge C
2918	% (\cref{lem:over_restrict_iso}); the geometric identification of the structure sheaves is the
2919	% layer above them.
2920	
2921	\begin{lemma}[Slice of opens equivalent to opens of the open subspace]
2922	  \label{lem:opens_overEquivalence_mathlib}
2923	  \lean{TopologicalSpace.Opens.overEquivalence}
2924	  \mathlibok
2925	  \textit{Provided by Mathlib (\texttt{Mathlib.Topology.Sheaves.Over}).}
2926	  For a topological space \(X\) and an open \(U \subseteq X\), the slice category of opens of
2927	  \(X\) over \(U\) (the opens of \(X\) contained in \(U\), with inclusions) is equivalent to the
2928	  opens of the subspace \(U\):
2929	  \((\mathrm{Opens}\,X)_{/U} \simeq \mathrm{Opens}(U)\). Mathlib supplies this underlying
2930	  equivalence of sites; it leaves the lift to sheaf categories as an explicit TODO.
2931	\end{lemma}
2932	
2933	\begin{lemma}[Sheaf categories of equivalent sites are equivalent]
2934	  \label{lem:equivalence_sheafCongr_mathlib}
2935	  \lean{CategoryTheory.Equivalence.sheafCongr}
2936	  \mathlibok
2937	  \textit{Provided by Mathlib (\texttt{Mathlib.CategoryTheory.Sites.Equivalence}).}
2938	  Let \(e : C \simeq D\) be an equivalence of categories carrying Grothendieck topologies \(J\)
2939	  on \(C\) and \(K\) on \(D\), and suppose \(e.\mathrm{inverse}\) is a dense subsite for
2940	  \((K, J)\). Then for any target category \(A\) the sheaf categories are equivalent:
2941	  \(\mathrm{Sheaf}(J, A) \simeq \mathrm{Sheaf}(K, A)\).
2942	\end{lemma}
2943	
2944	\begin{lemma}[Module sheaves transport across an equivalence of ringed sites]
2945	  \label{lem:pushforwardPushforwardEquivalence_mathlib}
2946	  \lean{SheafOfModules.pushforwardPushforwardEquivalence}
2947	  \mathlibok
2948	  \textit{Provided by Mathlib
2949	  (\texttt{Mathlib.Algebra.Category.ModuleCat.Sheaf.PushforwardContinuous}).}
2950	  Let \(e : C \simeq D\) be an equivalence of sites with both \(e.\mathrm{functor}\) and
2951	  \(e.\mathrm{inverse}\) continuous, and let \(S\) (a sheaf of rings on \(J\)) and \(R\) (a sheaf
2952	  of rings on \(K\)) be related by mutually inverse comparison maps across the continuous
2953	  pushforwards. Then the categories of sheaves of modules are equivalent,
2954	  \(\mathrm{SheafOfModules}\,R \simeq \mathrm{SheafOfModules}\,S\), compatibly with the
2955	  underlying ring-sheaf identification. This is the module-level lift used in step~3 of
2956	  \cref{lem:over_restrict_iso}.
2957	\end{lemma}
2958	
2959	\begin{lemma}\leanok
2960	[The over-equivalence functor is cocontinuous]
2961	  \label{lem:overEquivalence_functor_isCocontinuous}
2962	  \lean{AlgebraicGeometry.overEquivalence_functor_isCocontinuous}
2963	  \uses{lem:opens_overEquivalence_mathlib}
2964	  \textit{Topological layer of bridge C; fills the \texttt{Topology/Sheaves/Over.lean} TODO.}
2965	  The functor of \(\mathrm{Opens.overEquivalence}\,U\) (\cref{lem:opens_overEquivalence_mathlib})
2966	  is cocontinuous (cover-lifting) from the \(U\)-slice \(J_X|_U\) of the opens Grothendieck
2967	  topology of \(X\) to the opens Grothendieck topology \(J_U\) of the subspace \(U\).
2968	\end{lemma}
2969	\begin{proof}
2970	  \uses{lem:opens_overEquivalence_mathlib}
2971	  A sieve covers in the slice topology \(J_X|_U\) iff its image sieve covers in \(J_X\), and
2972	  covering for the opens topology is pointwise: a sieve covers iff its members' opens cover the
2973	  base set-theoretically. Given a point \(x\) of a slice object and a cover member in \(J_U\)
2974	  containing the image of \(x\), transport it across the open embedding \(U \hookrightarrow X\),
2975	  which is injective: the set-theoretic image of an open \(V \subseteq U\) is an open of \(X\)
2976	  contained in the base, a neighbourhood of \(x\) lying in the image sieve. This witnesses the
2977	  cover-lifting condition.
2978	\end{proof}
2979	
2980	\begin{lemma}\leanok
2981	[The over-equivalence inverse is cocontinuous]
2982	  \label{lem:overEquivalence_inverse_isCocontinuous}
2983	  \lean{AlgebraicGeometry.overEquivalence_inverse_isCocontinuous}
2984	  \uses{lem:opens_overEquivalence_mathlib}
2985	  \textit{Topological layer of bridge C; fills the \texttt{Topology/Sheaves/Over.lean} TODO.}
2986	  Symmetrically, the inverse of \(\mathrm{Opens.overEquivalence}\,U\) is cocontinuous from the
2987	  opens topology \(J_U\) of the subspace \(U\) to the \(U\)-slice \(J_X|_U\).
2988	\end{lemma}
2989	\begin{proof}
2990	  \uses{lem:opens_overEquivalence_mathlib}
2991	  As in \cref{lem:overEquivalence_functor_isCocontinuous}, reduce to the pointwise covering
2992	  criterion and the over-sieve image criterion; given a point and a slice-cover member, pull the
2993	  member back along the embedding \(U \hookrightarrow X\) (preimage of an open of \(X\) is an open
2994	  of the subspace) to obtain a cover member of \(J_U\) witnessing the lift.
2995	\end{proof}
2996	
2997	\begin{lemma}\leanok
2998	[The over-equivalence inverse is a dense subsite]
2999	  \label{lem:overEquivalence_inverse_isDenseSubsite}
3000	  \lean{AlgebraicGeometry.overEquivalence_inverse_isDenseSubsite}
3001	  \uses{lem:overEquivalence_functor_isCocontinuous, lem:overEquivalence_inverse_isCocontinuous}
3002	  \textit{Topological layer of bridge C; the dense-subsite witness assembled from the two
3003	  cocontinuities.}
3004	  The inverse of \(\mathrm{Opens.overEquivalence}\,U\) is a dense subsite for \((J_U, J_X|_U)\).
3005	  This is formal: an equivalence both of whose legs are cocontinuous
3006	  (\cref{lem:overEquivalence_functor_isCocontinuous},
3007	  \cref{lem:overEquivalence_inverse_isCocontinuous}) yields a dense subsite on its inverse.
3008	\end{lemma}
3009	
3010	\begin{lemma}\leanok
3011	[The over-equivalence functor is continuous]
3012	  \label{lem:overEquivalence_functor_isContinuous}
3013	  \lean{AlgebraicGeometry.overEquivalence_functor_isContinuous}
3014	  \uses{lem:overEquivalence_inverse_isCocontinuous}
3015	  \textit{Topological layer of bridge C; needed for the module-level lift of step~3.}
3016	  The functor of \(\mathrm{Opens.overEquivalence}\,U\) is continuous (cover-preserving) for
3017	  \((J_X|_U, J_U)\). It is obtained from the cocontinuity of the inverse
3018	  (\cref{lem:overEquivalence_inverse_isCocontinuous}) through the equivalence adjunction: the
3019	  left adjoint of a cocontinuous functor is continuous.
3020	\end{lemma}
3021	
3022	\begin{lemma}\leanok
3023	[The over-equivalence inverse is continuous]
3024	  \label{lem:overEquivalence_inverse_isContinuous}
3025	  \lean{AlgebraicGeometry.overEquivalence_inverse_isContinuous}
3026	  \uses{lem:overEquivalence_functor_isCocontinuous}
3027	  \textit{Topological layer of bridge C; needed for the module-level lift of step~3.}
3028	  Symmetrically, the inverse of \(\mathrm{Opens.overEquivalence}\,U\) is continuous for
3029	  \((J_U, J_X|_U)\), obtained from the cocontinuity of the functor
3030	  (\cref{lem:overEquivalence_functor_isCocontinuous}) through the equivalence adjunction.
3031	\end{lemma}
