3033	\begin{definition}\leanok
3034	[The over-site/open-subspace sheaf equivalence]
3035	  \label{def:overEquivalence_sheafCongr}
3036	  \lean{AlgebraicGeometry.overEquivalence_sheafCongr}
3037	  \uses{lem:opens_overEquivalence_mathlib, lem:equivalence_sheafCongr_mathlib,
3038	    lem:overEquivalence_inverse_isDenseSubsite}
3039	  \textit{Keystone of the topological layer of bridge C.}
3040	  For any category \(A\), the site equivalence \(\mathrm{Opens.overEquivalence}\,U\)
3041	  (\cref{lem:opens_overEquivalence_mathlib}) lifts to an equivalence of sheaf categories
3042	  \[
3043	    \mathrm{Sheaf}(J_X|_U,\, A) \;\simeq\; \mathrm{Sheaf}(J_U,\, A),
3044	  \]
3045	  obtained by feeding the dense-subsite witness
3046	  (\cref{lem:overEquivalence_inverse_isDenseSubsite}) to the general sheaf-congruence
3047	  construction (\cref{lem:equivalence_sheafCongr_mathlib}). This is exactly the equivalence left
3048	  as a TODO in Mathlib's \texttt{Topology/Sheaves/Over.lean}, and it is the object across which
3049	  \cref{lem:over_restrict_iso} transports the structure sheaf and the module \(M\).
3050	\end{definition}
3051	
3052	% --- (C, step 3) The module-level equivalence and its functor identification ---
3053	
3054	% The two blocks below are the module-category layer assembled on top of the topological
3055	% sheaf-congruence def:overEquivalence_sheafCongr: the step-3 equivalence of categories of sheaves of
3056	% modules (def:over_restrict_equiv) and the step-4 functor identification (lem:over_restrict_functor_iso)
3057	% whose object component is the slice-touching bridge lem:over_restrict_iso below. They are
3058	% project-bespoke infrastructure (no external source).
3059	
3060	\begin{definition}
3061	
3062	\leanok
3063	[The slice-to-geometric module-category equivalence (gap1, C, step 3)]
3064	  \label{def:over_restrict_equiv}
3065	  \lean{AlgebraicGeometry.Scheme.Modules.overRestrictEquiv}
3066	  \uses{def:overEquivalence_sheafCongr, lem:opens_overEquivalence_mathlib,
3067	    lem:pushforwardPushforwardEquivalence_mathlib, lem:overEquivalence_functor_isContinuous,
3068	    lem:overEquivalence_inverse_isContinuous}
3069	  \textit{Module-level lift of the topological bridge C; the step-3 equivalence on which the
3070	  slice-touching isomorphism is built.}
3071	  Let \(X\) be a scheme and \(U \subseteq X\) an open. The category of sheaves of modules over the
3072	  sliced structure sheaf \(\mathcal{O}_X.\mathrm{over}\,U\) on the slice site \(J.\mathrm{over}\,U\) is
3073	  equivalent to the category \(U.\mathrm{toScheme}.\mathrm{Modules}\) of sheaves of modules on the open
3074	  subscheme \(U.\mathrm{toScheme}\):
3075	  \[
3076	    \mathrm{SheafOfModules}\bigl(\mathcal{O}_X.\mathrm{over}\,U\bigr)
3077	      \;\simeq\; U.\mathrm{toScheme}.\mathrm{Modules}.
3078	  \]
3079	  This is the module-category lift of the topological sheaf equivalence
3080	  \cref{def:overEquivalence_sheafCongr}.
3081	\end{definition}
3082	\begin{proof}
3083	  \uses{def:overEquivalence_sheafCongr, lem:opens_overEquivalence_mathlib,
3084	    lem:pushforwardPushforwardEquivalence_mathlib, lem:overEquivalence_functor_isContinuous,
3085	    lem:overEquivalence_inverse_isContinuous}
3086	  Apply the module-sheaf transport \(\mathrm{pushforwardPushforwardEquivalence}\)
3087	  (\cref{lem:pushforwardPushforwardEquivalence_mathlib}) to the site equivalence
3088	  \(\mathrm{Opens.overEquivalence}\,U\) (\cref{lem:opens_overEquivalence_mathlib}), whose two legs are
3089	  both continuous (\cref{lem:overEquivalence_functor_isContinuous},
3090	  \cref{lem:overEquivalence_inverse_isContinuous}). The transport consumes a pair of mutually inverse
3091	  ring-sheaf comparison morphisms between the sliced structure sheaf
3092	  \(\mathcal{O}_X.\mathrm{over}\,U\) and the geometric structure sheaf
3093	  \(\mathcal{O}_{U.\mathrm{toScheme}}\); for these one takes the whiskered (co)unit of the site
3094	  equivalence \(\mathrm{Opens.overEquivalence}\,U\) into the structure presheaf, paired with the
3095	  identity. The identity is legal precisely because the geometric structure sheaf is
3096	  the transport of the sliced one across the ring-valued instance of
3097	  \cref{def:overEquivalence_sheafCongr} (this is step~2 of the bridge, which holds by
3098	  construction). Orienting the resulting equivalence so that its functor runs from the slice
3099	  side to the geometric side gives the stated equivalence.
3100	\end{proof}
3101	
3102	\begin{lemma}
3103	
3104	\leanok
3105	[Functor identification of the slice-to-geometric equivalence (gap1, C, step 4)]
3106	  \label{lem:over_restrict_functor_iso}
3107	  \lean{AlgebraicGeometry.Scheme.Modules.overRestrictFunctorIso}
3108	  \uses{def:over_restrict_equiv, lem:modules_restrictFunctor_mathlib,
3109	    lem:opens_overEquivalence_mathlib}
3110	  \textit{The composite of the slice functor with the step-3 equivalence is the geometric restriction
3111	  functor.}
3112	  With \(X\) and \(U \subseteq X\) as above, the composite of the abstract Grothendieck-slice functor
3113	  \(M \mapsto M.\mathrm{over}\,U\) (pushforward along the identity of the sliced ring sheaf) with the
3114	  functor of the step-3 equivalence (\cref{def:over_restrict_equiv}) is naturally isomorphic to the
3115	  geometric restriction functor along the open immersion \(U.\iota\):
3116	  \[
3117	    \bigl(\mathrm{pushforward}\,\mathbf{1}\bigr) \;\circ\; (\mathrm{overRestrictEquiv}\,U).\mathrm{functor}
3118	      \;\cong\; \mathrm{restrictFunctor}\,U.\iota
3119	  \]
3120	  (\cref{lem:modules_restrictFunctor_mathlib}).
3121	\end{lemma}
3122	\begin{proof}
3123	  \uses{def:over_restrict_equiv, lem:modules_restrictFunctor_mathlib,
3124	    lem:opens_overEquivalence_mathlib}
3125	  Both sides are pushforwards of sheaves of modules along the \emph{same} opens functor. Indeed the
3126	  opens functor of the open immersion factors as
3127	  \[
3128	    U.\iota.\mathrm{opensFunctor}
3129	      \;=\; (\mathrm{Opens.overEquivalence}\,U).\mathrm{inverse}\;\circ\;\mathrm{Over.forget}\,U
3130	  \]
3131	  (\cref{lem:opens_overEquivalence_mathlib}), an equality that holds by construction, and
3132	  \(\mathrm{restrictFunctor}\,U.\iota\) (\cref{lem:modules_restrictFunctor_mathlib}) is precisely
3133	  pushforward along \(U.\iota.\mathrm{opensFunctor}\). The left-hand composite is pushforward along the
3134	  factored functor on the right. Identify the two via the composition law for module-sheaf
3135	  pushforward (\(\mathrm{pushforwardComp}\)) followed by congruence of pushforward along the equal ring
3136	  morphisms (\(\mathrm{pushforwardCongr}\)); the required ring-morphism equality is routine.
3137	\end{proof}
3138	
3139	% --- (C) The single slice-touching bridge ---
3140	
3141	\begin{lemma}\leanok
3142	[The Grothendieck-slice restriction equals the geometric restriction (gap1, C)]
3143	  \label{lem:over_restrict_iso}
3144	  \lean{AlgebraicGeometry.Scheme.Modules.overRestrictIso}
3145	  \uses{lem:modules_restrictFunctor_mathlib, lem:modules_restrictFunctorIsoPullback_mathlib,
3146	    lem:isLocalization_basicOpen_mathlib, def:overEquivalence_sheafCongr,
3147	    lem:overEquivalence_functor_isContinuous, lem:overEquivalence_inverse_isContinuous,
3148	    lem:opens_overEquivalence_mathlib, lem:pushforwardPushforwardEquivalence_mathlib}
3149	  % NOTE: RESOLVED and axiom-clean. AlgebraicGeometry.Scheme.Modules.overRestrictIso
3150	  % now exists (#print axioms = {propext, Classical.choice, Quot.sound}); gap1 bridge C
3151	  % (steps 1->4) is fully closed. The step-2 geometric ring-sheaf identification collapsed to
3152	  % `rfl` (U.toScheme.ringCatSheaf is definitionally the transport of the sliced sheaf, via
3153	  % toScheme_presheaf_obj/map). The statement is routed through the step-3 equivalence functor:
3154	  % overRestrictIso : (overRestrictEquiv U).functor.obj (M.over U) ≅ (restrictFunctor U.ι).obj M.
3155	  \textit{The one lemma that must touch the Grothendieck slice site; everything downstream of it is
3156	  geometric.}
3157	  Let \(X\) be a scheme and \(U \subseteq X\) an open. The \emph{abstract Grothendieck-slice}
3158	  restriction \(M.\mathrm{over}\,U\) — an object of the category of sheaves of modules over the
3159	  sliced structure sheaf \(\mathcal{O}_X.\mathrm{over}\,U\) on the slice site \(J.\mathrm{over}\,U\) —
3160	  is canonically isomorphic to the \emph{geometric} restriction
3161	  \((\mathrm{restrictFunctor}\,U.\iota).\mathrm{obj}\,M\)
3162	  (\cref{lem:modules_restrictFunctor_mathlib}), equivalently to the pullback \(U.\iota^{*} M\)
3163	  (\cref{lem:modules_restrictFunctorIsoPullback_mathlib}), as a sheaf of modules on the small Zariski
3164	  site of the open subscheme \(U.\mathrm{toScheme}\). The isomorphism is induced by the equivalence
3165	  of sites \(J.\mathrm{over}\,U \simeq \mathrm{Opens}(U.\mathrm{toScheme})\) coming from the opens
3166	  functor of the open immersion \(U.\iota\), under which the sliced sheaf of rings
3167	  \(\mathcal{O}_X.\mathrm{over}\,U\) corresponds to the structure sheaf of \(U.\mathrm{toScheme}\).
